const a={name:"Lagerblad",icon:"lagerblad",category:"kryddor",family:"Lagerväxter",familyLatin:"Lauraceae",perennial:!0,difficulty:"Avancerad",difficultyWhy:"Lagerblad är en medelhavsbuske som inte är vinterhärdig i Sverige. Hon måste odlas i kruka och tas in varje höst. Inte svår att hålla vid liv om du har en ljus, sval plats att övervintras på - men det kräver planering och utrymme.",zones:{outdoor:null,indoor:[1,2,3,4,5,6,7,8],greenhouse:[1,2,3]},days:"Löpande bladskörd från år 2",spacing:"1 per kruka",spacingNote:"Minst 30 cm diameter",rowSpacing:"-",depth:"1 cm",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Lagerblad vill ha så mycket sol som möjligt under sommaren - minst 6-8 timmar om dagen. Ställ henne utomhus på den soligaste platsen du har. Tolererar halvskugga men blir glesare och mindre aromatisk."},temperature:{min:-5,max:35,ideal:"15-25°C",detail:"En medelhavsväxt som klarar kortvarig frost ner till -5°C men inte svenska vintrar. Övervintras ljust och svalt inomhus vid 5-10°C. Temperatursvängningar gör henne stressad - flytta inte fram och tillbaka i onödan."},wind:{level:"Skyddat",detail:"Föredrar ett skyddat läge, gärna vid en södervägg som ger extra värme och vindskydd. Kall nordanvind i kombination med frost är hennes värsta fiende."}},watering:{need:"Medel",icon:"water",summary:"Lagerblad vill ha rejäla vattningar men måste få torka upp lite emellan. Tänk medelhavsklimat: kraftiga regnskurar följda av soliga, torra dagar.",phases:[{phase:"Sommar (aktiv tillväxt)",need:"Medel",tip:"Vattna rejält så hela jordklumpen blir genomblöt, låt sedan torka upp något innan nästa vattning. Fingret i jorden 2-3 cm ner - torrt? Dags att vattna."},{phase:"Höst (inför övervintring)",need:"Låg",tip:"Minska vattningen gradvis när du tar in henne. Hon ska trappa ner och förbereda sig för vila."},{phase:"Vinter (vila)",need:"Låg",tip:"Vattna sparsamt - kanske varannan vecka. Jorden ska inte vara knastertorr, men heller aldrig blöt. Kall, fuktig jord = rotröta."},{phase:"Vår (uppvakning)",need:"Medel",tip:"Öka vattningen sakta när dagarna blir längre och hon börjar skjuta nya skott."}],mistakes:["Övervattnar under vintern - den absolut vanligaste dödsorsaken för kruklager i Sverige","Ställer henne på ett fat med stående vatten - rötterna ruttnar","Glömmer att vattna under sommaren när hon står ute i full sol och avdunstningen är hög"],tip:"Låt alltid överskottsvatten rinna av. Lagerblad i kruka vill aldrig stå i vatten - men torka ut helt ska hon inte heller göra."},soil:"Väldränerad jord är viktigast. Blanda vanlig planteringsjord med perlit eller grus så vattnet rinner igenom snabbt. Medelhavsjord från trädgårdshandeln fungerar utmärkt.",soilTips:["Blanda 2 delar planteringsjord med 1 del perlit eller grus för perfekt dränering","Lägg ett lager lecakulor eller krukskärvor i botten av krukan","Omplanteras inte ofta - byt jord vart 3-4 år eller toppdress med ny jord","Undvik torv som enda substrat - den blir vattenstötande när den torkar ut"],timeline:{1:[{phase:"Ut på balkong/terrass",months:"Maj",icon:"seedling"},{phase:"Skörd löpande",months:"Maj-okt",icon:"harvest"},{phase:"Beskärning",months:"Apr",icon:"flower"},{phase:"In för övervintring",months:"Okt",icon:"indoor"}],4:[{phase:"Ut på balkong/terrass",months:"Jun",icon:"seedling"},{phase:"Skörd löpande",months:"Jun-sep",icon:"harvest"},{phase:"Beskärning",months:"Apr-maj",icon:"flower"},{phase:"In för övervintring",months:"Sep",icon:"indoor"}],6:[{phase:"Ut (skyddat läge)",months:"Jun-jul",icon:"seedling"},{phase:"Skörd löpande",months:"Jul-aug",icon:"harvest"},{phase:"Beskärning",months:"Maj",icon:"flower"},{phase:"In för övervintring",months:"Aug-sep",icon:"indoor"}]},nutritionData:[{month:"Apr",N:3,P:2,K:2},{month:"Maj",N:5,P:3,K:3},{month:"Jun",N:6,P:3,K:4},{month:"Jul",N:5,P:3,K:4},{month:"Aug",N:4,P:2,K:3},{month:"Sep",N:2,P:1,K:2}],nutritionTips:[{timing:"Vår (april-maj)",tip:"Ge en lätt giva flytande näring när hon vaknar och börjar skjuta nya blad. Eko-gödsel för krukväxter fungerar bra."},{timing:"Sommar (juni-aug)",tip:"Gödsla varannan vecka med svag dos flytande näring. Lagerblad är ingen storätare men uppskattar regelbunden, modest matning."},{timing:"Höst-vinter",tip:"Sluta gödsla helt från september. Hon ska vila, inte växa. Ny näring i kall jord gör mer skada än nytta."}],companions:{good:[{id:"timjan",name:"Timjan",icon:"herb",why:"Båda mediterrana och trivs i samma soliga, torra förhållanden. Perfekt sällskap i en medelhavskrukgrupp på balkongen."},{id:"rosmarin",name:"Rosmarin",icon:"herb",why:"Samma krav på sol, dränering och övervintring. De delar livsstil och kan stå sida vid sida hela året."},{id:"salvia",name:"Salvia",icon:"herb",why:"Ännu en medelhavsgranne som vill ha exakt samma behandling. Tillsammans bildar de bouquet garni-trion."}],bad:[{id:"basilika",name:"Basilika",icon:"herb",why:"Basilika vill ha rik, fuktig jord och massor av vatten. Raka motsatsen till vad lagerblad behöver."},{id:"mynta",name:"Mynta",icon:"herb",why:"Mynta är aggressiv, fuktälskande och tar över varje kruka den kommer i närheten av."}]},rotation:{avoid:[{name:"Inte relevant"}],avoidWhy:"Lagerblad odlas i kruka och står på samma plats i många år. Växtföljd är inte relevant.",goodBefore:[{name:"Inte relevant"}],goodBeforeWhy:"Perenn krukväxt - växtföljd gäller inte.",goodAfter:[{name:"Inte relevant"}],goodAfterWhy:"Perenn krukväxt - växtföljd gäller inte."},varieties:[{name:"Laurus nobilis (vanlig lagerbuske)",zones:[1,2,3,4,5,6,7,8],note:'Den enda arten som odlas. Köps enklast som färdig planta från trädgårdshandeln. Säljs som "lagerträd" eller "äkta lager". Alla plantor ger samma aromatiska blad.'},{name:"Aurea (guldlager)",zones:[1,2,3],note:"Dekorativ sort med gyllene unga blad som mörknar med åldern. Samma arom som den gröna. Lite mer värmekrävande och passar bäst i zon 1-3."}],problems:[{name:"Sköldlöss",symptom:'Bruna, ovala "prickar" som sitter fast på undersidan av bladen och längs grenarna. Klibbigt, blankt utsöndrat socker (honungsdagg).',fix:"Skrapa bort manuellt med nageln eller en gammal tandborste. Behandla med rapsolja-baserat medel. Kontrollera regelbundet - de är svåra att bli av med helt."},{name:"Bladlöss",symptom:"Små gröna eller svarta insekter på unga skott. Krusade, deformerade nya blad.",fix:"Spola av med hård vattenstråle. Behandla med såpvatten (1 tsk flytande tvål per liter vatten). Gynna nyckelpigor utomhus."},{name:"Brunfläckiga blad (övervattning)",symptom:"Bruna, mjuka fläckar på bladen. Gulnande blad som faller av. Dålig lukt från jorden.",fix:"Minska vattningen omedelbart. Låt jorden torka upp. Kontrollera dräneringen - finns det hål i botten? Byt jord om den luktar illa."},{name:"Frost-/kylskada",symptom:"Bruna, torra blad efter en kall natt. Bark som spricker. Hela grenar som dör.",fix:"Klipp bort skadat material på våren och vänta. Lagerblad kan ofta återhämta sig från roten om stammen klarat sig. Flytta in henne tidigare nästa höst."}],goodToKnow:[{icon:"warning",title:"Övervintring är nyckeln",text:"Lagerblad klarar INTE svensk vinter utomhus. Ta in henne i ett ljust, svalt rum (5-10°C) innan första frosten. Ouppvärmd glasveranda, trappuppgång eller garage med fönster funkar perfekt.",severity:"warning"},{icon:"warning",title:"Inte i vardagsrummet",text:"Vanligt misstag: ställa lagerbusken i varmt vardagsrum vintertid. Hon vill ha SVALKA och vila, inte 22°C och torr luft. Resultatet blir sköldlöss och tappade blad.",severity:"warning"},{icon:"tip",title:"Torkade blad är smakrikare",text:"Färska lagerblad är ganska milda. Det är först efter 1-2 veckors torkning som de eteriska oljorna koncentreras och den klassiska lagerbladsdoften och smaken utvecklas fullt ut.",severity:"tip"},{icon:"tip",title:"Bouquet garni-klassikern",text:"Lagerblad, timjan och persilja - bundna ihop med en bit bomullssnöre. DEN klassiska franska kryddbuketten som gör varje gryta, soppa och buljong till något alldeles extra.",severity:"tip"},{icon:"tip",title:"Gammal symbolväxt",text:'Lagerkransen var den högsta utmärkelsen i antikens Grekland och Rom. Ordet "laureat" (som i Nobelpristagare) kommer från Laurus. En växt med 3000 års historia i din kruka!',severity:"tip"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Lagerblad är extremt långsam att dra från frö - groningen kan ta månader och växten behöver år innan den är användbar. Köp en färdig planta istället! Det sparar dig bokstavligen åratal av väntan.",steps:["Köp en liten lagerbuske (Laurus nobilis) i trädgårdshandeln (absolut enklast)","Plantera om i en kruka med bra dränering - lecakulor i botten, perlit i jorden","Ställ ljust och soligt inomhus eller utomhus (efter sista frost)","Börja plocka enstaka blad efter att plantan etablerat sig (första sommaren)","Ta in före första frosten på hösten till ljust, svalt utrymme (5-10°C)","Beskär på våren för att hålla formen kompakt och stimulera nya skott"],tips:["Köp planta, inte frö. Lagerblad från frö tar 1-2 månader att gro och flera år innan den ger användbar skörd","Sticklingar fungerar men tar 3-6 månader att rota sig. Halvförvedad skott på sensommaren ger bäst resultat","Beskärningsrester kan torkas och användas som krydda direkt!"],indoorWeeks:null},seedSaving:{difficulty:"Avancerad",type:"Insektspollinerad",biennial:!1,description:"Lagerblad blommar sällan i svensk odling och sätter ännu mer sällan frö. Förökning genom sticklingar är mycket mer praktiskt. Fröna behöver dessutom stratifiering (köldbehandling) för att gro.",steps:["Lagerblad är tvåbyggare - du behöver både han- och honplanta för frukt","Blomning sker sällan inomhus i Sverige - kräver somrar utomhus i skyddat, varmt läge","Om bären bildas: vänta tills de är helt svarta och mogna (oktober-november)","Rensa bort fruktköttet och tvätta fröna","Stratifiera: lägg fröna i fuktig sand i kylen i 4-6 veckor","Så i fuktig jord vid 15-20°C. Groning kan ta 1-6 månader!"],isolation:"Inte relevant i Sverige - lagerblad blommar sällan och det finns bara en art.",storageYears:"1 år (grobarhet sjunker snabbt - använd färskt frö)",tip:"Glöm frö - ta sticklingar istället. Klipp 10-15 cm halvförvedad gren på sensommaren, doppa i rothormon och sätt i fuktig perlit. Mycket enklare och snabbare."},storage:{shelfLife:"Färska blad 2-4 veckor, torkade 1-2 år",methods:[{method:"Torkning (bäst!)",icon:"storage",duration:"1-2 år",description:"Lägg bladen på ett nät eller häng kvistar i en torr, mörk plats. Torka i 1-2 veckor. Torkade lagerblad är faktiskt smakrikare än färska - de eteriska oljorna koncentreras.",best:!0},{method:"Färsk i kyl",icon:"water",duration:"2-4 veckor",description:"Lägg bladen i en plastpåse eller burk i kylen. Lagerbladets läderartade blad håller sig förvånansvärt länge färska.",best:!1},{method:"Frysning",icon:"snowflake",duration:"6+ månader",description:"Lägg hela blad i fryspåse. Kan användas direkt från frysen i grytor och soppor.",best:!1}],tips:["Torkade lagerblad i lufttät burk, mörkt och svalt - håller sig i 1-2 år med bibehållen arom","Knäck eller vik bladet innan du lägger det i grytan - frigör mer smak","Ta ALLTID bort lagerbladet innan servering - de blir aldrig mjuka och kan fastna i halsen","Byt ut dina torkade lagerblad en gång om året - efter det tappar de smak"]},harvestCalc:{minPerSqm:.05,maxPerSqm:.15,unit:"kg"},harvest:{label:"Skörd & användning",method:"Plocka enstaka blad löpande, välj mogna (mörkgröna) blad",description:"Plocka blad efter behov under hela växtsäsongen. Välj de mörkgröna, fullt utvecklade bladen - de har mest smak. Plocka inte mer än en tredjedel av bladen åt gången så busken mår bra.",uses:[{use:"Grytor & soppor",tip:"DEN klassiska användningen. Lägg ett lagerblad i varje gryta, soppa eller buljong. Smaken är subtil men gör enorm skillnad - testa att laga samma rätt med och utan."},{use:"Marinader",tip:"Lagerblad i marinader för kött och fisk ger en fin, djup smak. Krossa bladet lite först så de eteriska oljorna frigörs snabbare."},{use:"Inläggningar",tip:"Lagerblad i ättikslag för inlagd gurka, rödbetor och sill. En svensk klassiker som ger karaktär och djup."},{use:"Mjölksås & bechamel",tip:"Värm mjölken med ett lagerblad innan du gör sås. Subtilt men fantastiskt - det lilla extra som gör en enkel gräddsås till magi."}]}};export{a as lagerblad};
